// Construir filas — parsea las tablas HTML de SISET (CONSAR) por AFORE.
// Fuentes: md=38 Recursos (AUM), md=40 Cuentas, md=42 Traspasos. Mensual.
const AFORES=[['azteca','Azteca'],['banamex','Citibanamex'],['coppel','Coppel'],
 ['inbursa','Inbursa'],['invercap','Invercap'],['pensionissste','PensionISSSTE'],
 ['principal','Principal'],['profuturo','Profuturo'],['sura','SURA'],['xxi banorte','Banorte']];

function tabla(html){
  const text=String(html||'').replace(/<[^>]+>/g,' ').replace(/&nbsp;/g,' ').replace(/\s+/g,' ').toLowerCase();
  const pos=AFORES.map(([k])=>({k,i:text.indexOf(k)})).filter(o=>o.i>=0).sort((a,b)=>a.i-b.i);
  const res={};
  pos.forEach((o,idx)=>{
    const start=o.i+o.k.length;
    let end;
    if(idx+1<pos.length) end=pos[idx+1].i;
    else { const t=text.indexOf(' total',start); end=t>=0?t:text.length; }
    const slice=text.slice(start,end);
    res[o.k]=(slice.match(/-?\d[\d,]*\.?\d*/g)||[]).map(s=>parseFloat(s.replace(/,/g,'')));
  });
  const m=text.match(/cierre de ([a-zñ]+ de \d{4})/);
  res._periodo=m?m[1]:null;
  return res;
}

const recursos=tabla($('Recursos (AUM)').first().json.data);   // AUM = 5º número (Total Admin. por las Afores)
const cuentas =tabla($('Cuentas').first().json.data);           // [regSiefores, regBanxico, asignados, total]
const traspasos=tabla($('Traspasos').first().json.data);        // [recibidos, cedidos, netos]
const periodo = cuentas._periodo || recursos._periodo || null;

const rows=AFORES.map(([k,afore])=>{
  const r={afore, periodo};
  if(cuentas[k]&&cuentas[k].length){
    r.cuentas=cuentas[k][cuentas[k].length-1];                       // total (incluye asignadas)
    if(cuentas[k].length>=2) r.cuentas_registradas=cuentas[k][0]+cuentas[k][1]; // registrados (Siefores+Banxico)
  }
  if(recursos[k]&&recursos[k].length>=5) r.aum_mdp=recursos[k][4];
  if(traspasos[k]&&traspasos[k].length>=2){ r.recibidos_cuentas=traspasos[k][0]; r.cedidos_cuentas=traspasos[k][1]; }
  return r;
}).filter(r=>r.cuentas_registradas!=null||r.aum_mdp!=null||r.cedidos_cuentas!=null);

return [{ json: { rows, _debug: { periodo, ejemplo: rows[0] } } }];
